using HaCreator.MapEditor;using HaCreator.MapEditor.Instance;using System;using System.Windows;
namespace HaCreator.GUI.InstanceEditor{public partial class TnSelector:EditorBase{public static string Show(Board board){TnSelector selector=new(board);selector.ShowDialog();return selector.result;}private string result;public TnSelector(Board board){InitializeComponent();foreach(PortalInstance portal in board.BoardItems.Portals)if(!string.IsNullOrEmpty(portal.pn)&&portal.pn!="sp"&&portal.pn!="pt")pnList.Items.Add(portal.pn);}protected override void cancelButton_Click(object s,EventArgs e)=>Close();protected override void okButton_Click(object s,EventArgs e){result=pnList.SelectedItem as string;Close();}private void Cancel_Click(object s,RoutedEventArgs e)=>cancelButton_Click(s,EventArgs.Empty);private void Ok_Click(object s,RoutedEventArgs e)=>okButton_Click(s,EventArgs.Empty);}}
